const data = $input.item.json;
const errors = [];

const start = new Date(data['Start date']);
const end = new Date(data['End date']);
if (isNaN(start) || isNaN(end)) {
  errors.push("Invalid date format.");
} else if (end <= start) {
  errors.push("End date must be after start date.");
}

const budget = Number(data['Budget']);
if (isNaN(budget) || budget <= 0) {
  errors.push("Budget must be a positive number.");
}

const travelers = Number(data['Number of travelers']);
if (isNaN(travelers) || !Number.isInteger(travelers) || travelers <= 0) {
  errors.push("Number of travelers must be a positive whole number.");
}

return [{ json: { ...data, isValid: errors.length === 0, errors } }];

