parameters.jsCode:
const data = $json.output ? $json.output : $json;

const esc = (s) => (s === undefined || s === null) ? "" : String(s);
const money = (n) => "₹" + Number(n || 0).toLocaleString("en-IN");
const img = (url, alt) => url
  ? `<img src="${esc(url)}" alt="${esc(alt)}" style="width:100%;max-width:500px;height:200px;object-fit:cover;border-radius:10px;display:block;margin-bottom:10px;" />`
  : "";
const btn = (url, label) => url
  ? `<a href="${esc(url)}" style="display:inline-block;background:#0f766e;color:#ffffff;text-decoration:none;padding:10px 18px;border-radius:6px;font-size:14px;font-weight:600;margin-top:8px;">${label}</a>`
  : "";

// ---------- FLIGHTS ----------
const flights = Array.isArray(data.flights) ? data.flights : [];
const flightsHtml = flights.map(f => `
  <table role="presentation" width="100%" style="background:#ffffff;border:1px solid #e5e7eb;border-radius:10px;margin-bottom:16px;padding:16px;">
    <tr><td>
      ${img(f.image, f.airline)}
      <div style="font-size:16px;font-weight:700;color:#111827;">${esc(f.airline)} · ${esc(f.flight_number)}</div>
      <div style="font-size:14px;color:#4b5563;margin:6px 0;">
        ${esc(f.departure_airport)} ${esc(f.departure_time)} &rarr; ${esc(f.arrival_airport)} ${esc(f.arrival_time)}
      </div>
      <div style="font-size:18px;font-weight:700;color:#0f766e;">${money(f.price)}</div>
      ${btn(f.booking_url, "View Flight")}
    </td></tr>
  </table>
`).join("");

// ---------- ACCOMMODATIONS ----------
const accommodations = Array.isArray(data.accommodations) ? data.accommodations : (data.accommodation ? [data.accommodation] : []);
const accommodationsHtml = accommodations.map(a => `
  <table role="presentation" width="100%" style="background:#ffffff;border:1px solid #e5e7eb;border-radius:10px;margin-bottom:16px;padding:16px;">
    <tr><td>
      ${img(a.image, a.name)}
      <div style="font-size:16px;font-weight:700;color:#111827;">${esc(a.name)}</div>
      <div style="font-size:13px;color:#6b7280;margin:4px 0;">${esc(a.address)}</div>
      <div style="font-size:14px;color:#4b5563;">${money(a.price_per_night)} / night &middot; Total: ${money(a.total_price)}</div>
      ${btn(a.booking_url, "View Hotel")}
    </td></tr>
  </table>
`).join("");

// ---------- FULL DAY-BY-DAY ITINERARY (every day, guaranteed) ----------
const itinerary = Array.isArray(data.itinerary) ? data.itinerary : [];
const itineraryHtml = itinerary.map(day => {
  const acts = Array.isArray(day.activities) ? day.activities : [];
  const actsHtml = acts.map(a => `
    <div style="margin-bottom:14px;">
      ${img(a.image, a.title)}
      <div style="font-size:14px;color:#111827;font-weight:600;">${esc(a.title)}</div>
    </div>
  `).join("");
  return `
    <table role="presentation" width="100%" style="background:#f9fafb;border-radius:10px;margin-bottom:18px;padding:16px;">
      <tr><td>
        <div style="font-size:16px;font-weight:700;color:#0f766e;margin-bottom:10px;">
          Day ${esc(day.day)} &middot; ${esc(day.date)}
        </div>
        ${actsHtml || '<div style="color:#9ca3af;font-size:13px;">No activities planned</div>'}
      </td></tr>
    </table>
  `;
}).join("");

// ---------- ACTIVITIES REFERENCE GALLERY (optional extra section) ----------
const activities = Array.isArray(data.activities) ? data.activities : [];
const activitiesHtml = activities.map(a => `
  <table role="presentation" width="48%" style="display:inline-block;vertical-align:top;background:#ffffff;border:1px solid #e5e7eb;border-radius:10px;margin:1%;padding:12px;">
    <tr><td>
      ${img(a.image, a.name)}
      <div style="font-size:14px;font-weight:700;color:#111827;">${esc(a.name)}</div>
      <div style="font-size:12px;color:#6b7280;margin-top:4px;">${esc(a.description)}</div>
    </td></tr>
  </table>
`).join("");

// ---------- COST SUMMARY ----------
const cs = data.cost_summary || {};
const costHtml = `
  <table role="presentation" width="100%" style="background:#111827;color:#ffffff;border-radius:10px;padding:16px;margin-bottom:16px;">
    <tr><td style="font-size:14px;padding:4px 0;">Flights</td><td align="right">${money(cs.flights_total)}</td></tr>
    <tr><td style="font-size:14px;padding:4px 0;">Accommodation</td><td align="right">${money(cs.accommodation_total)}</td></tr>
    <tr><td style="font-size:14px;padding:4px 0;">Activities</td><td align="right">${money(cs.activities_total)}</td></tr>
    <tr><td style="font-size:14px;padding:4px 0;">Food</td><td align="right">${money(cs.food_total)}</td></tr>
    <tr><td style="font-size:16px;font-weight:700;padding-top:10px;border-top:1px solid #374151;">Grand Total</td>
        <td align="right" style="font-size:16px;font-weight:700;padding-top:10px;border-top:1px solid #374151;">${money(cs.grand_total)}</td></tr>
  </table>
`;

return [{
  json: {
    ...data,
    html_flights: flightsHtml,
    html_accommodations: accommodationsHtml,
    html_itinerary: itineraryHtml,
    html_activities_gallery: activitiesHtml,
    html_cost_summary: costHtml,
    day_count: itinerary.length
  }
}];
